class Solution {
public:
    int subarraySum(int nums[], int n, int k) {
        int count = 0, sum = 0;
        unordered_map<int, int> map;
        map[0] = 1;  // Initialize the map with sum 0 occurring once
        for (int i = 0; i < n; i++) {
            sum += nums[i];  // Calculate cumulative sum

            // Check if (sum - k) exists in the map
            if (map.find(sum - k) != map.end()) {
                count += map[sum - k];  // Increment count by the frequency of (sum - k)
            }
            map[sum]++;
        }
        return count;
    }
};

