#define MAX 100000

typedef struct {
    int key;
    int value;
} Pair;

Pair map[MAX];
int size = 0;

// Function to find index of key
int find(int key) {
    for (int i = 0; i < size; i++) {
        if (map[i].key == key) {
            return i;
        }
    }
    return -1;
}

// Function to get value of key
int get(int key) {
    int idx = find(key);
    if (idx == -1) return 0;
    return map[idx].value;
}

// Function to increment value of key
void increment(int key) {
    int idx = find(key);
    if (idx == -1) {
        map[size].key = key;
        map[size].value = 1;
        size++;
    } else {
        map[idx].value++;
    }
}

int subarraySum(int nums[], int n, int k) {
    int count = 0, sum = 0;

    // Initialize map with sum 0 occurring once
    increment(0);

    for (int i = 0; i < n; i++) {
        sum += nums[i];

        // Check if (sum - k) exists
        count += get(sum - k);

        // Add current sum to map
        increment(sum);
    }

    return count;
}

