// Function to find the number of subarrays with sum equal to k
function subarraySum(nums, k) {
    let count = 0;
    let sum = 0;
    let prefixSumMap = new Map();
    prefixSumMap.set(0, 1);  // Initialize the map with sum 0 occurring once

    for (let i = 0; i < nums.length; i++) {
        sum += nums[i];  // Calculate cumulative sum

        // Check if (sum - k) exists in the map
        if (prefixSumMap.has(sum - k)) {
            count += prefixSumMap.get(sum - k);  // Increment count by the frequency of (sum - k)
        }

        // Update the prefix sum frequency in the map
        if (prefixSumMap.has(sum)) {
            prefixSumMap.set(sum, prefixSumMap.get(sum) + 1);
        } else {
            prefixSumMap.set(sum, 1);
        }
    }

    return count;
}
